/**
 * BULK TOKEN MANAGEMENT SUITE
 * Combined macro providing all bulk token operations in one interface
 */

const selectedTokens = canvas.tokens.controlled;

if (selectedTokens.length === 0) {
  ui.notifications.warn("Please select one or more tokens first.");
  return;
}

// Light configurations for the token lights feature
const lightConfigs = {
  def: {
    label: "Default",
    config: { dim: 0, bright: 0 },
  },
  tokenlight: {
    label: "Token Light",
    config: {
      angle: 360,
      dim: 1,
      bright: 0,
      color: "#80ff80",
      luminosity: 0.5,
      attenuation: 1,
      coloration: 0,
      animation: {
        type: "smokepatch",
      }
    },
  },
  loopylight: {
    label: "Loopy",
    config: {
      angle: 360,
      dim: 1,
      bright: 0,
      color: "#24C1ED",
      luminosity: 0.5,
      attenuation: 1,
      coloration: 0,
      animation: {
        type: "witchwave",
      }
    },
  },
  crazylight: {
    label: "Madness",
    config: {
      angle: 360,
      dim: 1,
      bright: 0,
      color: "#D60CF5",
      luminosity: 0.5,
      attenuation: 1,
      coloration: 0,
      animation: {
        type: "witchwave",
      }
    },
  },
  redlight: {
    label: "Red",
    config: {
      angle: 360,
      dim: 1,
      bright: 0,
      color: "#ff0000",
      luminosity: 0.5,
      attenuation: 1,
      coloration: 0,
      animation: {
        type: "smokepatch",
      }
    }
  },
  queenlight: {
    label: "Queenspawn",
    config: {
      angle: 360,
      dim: 1,
      bright: 0,
      color: "#ff0000",
      luminosity: 0.5,
      attenuation: 1,
      coloration: 1,
      animation: {
        type: "ghost",
      }
    }
  }
};

// Auto-Attack UUID - USER MUST SET THIS
const autoAttackUUID = "YOURUUIDHERE"; // Replace with your actual Auto-Attack item UUID

// Main dialog
new Dialog({
  title: `Bulk Token Manager - ${selectedTokens.length} Token(s) Selected`,
  content: `
    <div style="display: flex; flex-direction: column; gap: 15px; padding: 10px 0;">
      <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">
        <!-- Column 1 -->
        <div style="display: flex; flex-direction: column; gap: 10px;">
        <button id="add-auto-attack" style="text-align: left; padding: 8px">
          <i class="fas fa-plus-circle"></i> Add Auto-Attack
        </button>
        <button id="set-image" style="text-align: left; padding: 8px">
          <i class="fas fa-image"></i> Set Token Image
        </button>
          <button id="set-name-display" style="text-align: left; padding: 8px">
            <i class="fas fa-eye"></i> Set Name Display
          </button>
          <button id="clear-effects" style="text-align: left; padding: 8px">
            <i class="fas fa-broom"></i> Clear All Effects
          </button>
          <button id="token-lights" style="text-align: left; padding: 8px">
            <i class="fas fa-lightbulb"></i> Configure Lights
          </button>
        </div>

        <!-- Column 2 -->
        <div style="display: flex; flex-direction: column; gap: 10px;">
        <button id="remove-auto-attack" style="text-align: left; padding: 8px">
          <i class="fas fa-minus-circle"></i> Remove Auto-Attack
        </button>
        <button id="set-name" style="text-align: left; padding: 8px">
          <i class="fas fa-tag"></i> Set Token Name
        </button>
        <button id="show-wounds" style="text-align: left; padding: 8px">
          <i class="fas fa-heartbeat"></i> Set Wounds Display
        </button>
        <button id="reset-wounds" style="text-align: left; padding: 8px">
          <i class="fas fa-heart"></i> Reset Wounds to 0
        </button>
        <button id="set-disposition" style="text-align: left; padding: 8px">
          <i class="fas fa-users"></i> Set Disposition
        </button>
        </div>
      </div>

      <div style="border-top: 1px solid #666; padding-top: 10px; font-size: 0.8em; color: #999;">
        <strong>Selected Tokens:</strong> ${selectedTokens.map(t => t.name).join(', ')}
      </div>
      <div style="font-size: 0.7em; color: #ff6b6b; padding: 5px; background: #fff3f3; border-radius: 3px;">
        <strong>Note:</strong> Remember to set your Auto-Attack UUID in the macro code (line 97)
      </div>
    </div>
  `,
  buttons: {
    close: {
      icon: '<i class="fas fa-times"></i>',
      label: "Close"
    }
  },
  render: (html) => {
    // Clear Effects
    html.find('#clear-effects').click(async () => {
      let clearedCount = 0;
      for (const tkn of selectedTokens) {
        if (tkn.actor) {
          try {
            const removeList = tkn.actor.temporaryEffects.map(e => e.id);
            if (removeList.length > 0) {
              await tkn.actor.deleteEmbeddedDocuments("ActiveEffect", removeList);
            }
            clearedCount++;
          } catch (error) {
            console.error(`Failed to clear effects for token ${tkn.name}:`, error);
          }
        }
      }
      ui.notifications.info(`Cleared effects from ${clearedCount} token(s)`);
    });

    // Reset Wounds
    html.find('#reset-wounds').click(async () => {
      let updatedCount = 0;
      for (const tkn of selectedTokens) {
        if (tkn.actor) {
          try {
            await tkn.actor.update({"system.combat.wounds.value": 0});
            updatedCount++;
          } catch (error) {
            console.error(`Failed to update wounds for token ${tkn.name}:`, error);
          }
        }
      }
      ui.notifications.info(`Reset wounds for ${updatedCount} out of ${selectedTokens.length} selected tokens.`);
    });

    // Set Image
    html.find('#set-image').click(() => {
      const defaultImage = "tokens/icons/Icons_Skull.png";

      new Dialog({
        title: "Set Token Image",
        content: `
          <div style="display: flex; flex-direction: column; gap: 10px;">
            <p>Set image for ${selectedTokens.length} selected token(s)</p>
            <div style="display: flex; gap: 5px;">
              <button id="search-image" style="flex: 1;">
                <i class="fas fa-search"></i> Browse Image
              </button>
              <button id="default-image" style="flex: 1;">
                <i class="fas fa-skull"></i> Use Default
              </button>
            </div>
          </div>
        `,
        buttons: {
          cancel: {
            icon: '<i class="fas fa-times"></i>',
            label: "Cancel"
          }
        },
        render: (innerHtml) => {
          innerHtml.find('#search-image').click(async () => {
            const fp = new FilePicker({
              type: "image",
              current: defaultImage,
              callback: async (path) => {
                const updates = selectedTokens.map(token => 
                  token.document.update({ texture: { src: path } })
                );
                await Promise.all(updates);
                ui.notifications.info(`Updated ${selectedTokens.length} token images!`);
              }
            });
            await fp.browse();
          });

          innerHtml.find('#default-image').click(async () => {
            const updates = selectedTokens.map(token => 
              token.document.update({ texture: { src: defaultImage } })
            );
            await Promise.all(updates);
            ui.notifications.info(`Updated ${selectedTokens.length} token images with default!`);
          });
        }
      }).render(true);
    });

    // Set Name
    html.find('#set-name').click(() => {
      new Dialog({
        title: "Set Token Names",
        content: `
          <div style="display: flex; flex-direction: column; gap: 10px; padding: 10px 0;">
            <label for="tokenName">Enter Name for Selected Tokens:</label>
            <input type="text" id="tokenName" value="Imperial Citizen" style="padding: 5px;">
            <p>This will update ${selectedTokens.length} selected token(s)</p>
          </div>
        `,
        buttons: {
          apply: {
            icon: '<i class="fas fa-check"></i>',
            label: "Apply",
            callback: (innerHtml) => {
              const newName = innerHtml.find('#tokenName').val();
              if (!newName.trim()) {
                ui.notifications.warn("Please enter a valid name.");
                return;
              }
              const tokenUpdates = selectedTokens.map(token => ({
                _id: token.id,
                "name": newName
              }));
              canvas.scene.updateEmbeddedDocuments('Token', tokenUpdates);
              ui.notifications.info(`Updated ${tokenUpdates.length} tokens to "${newName}".`);
            }
          },
          cancel: {
            icon: '<i class="fas fa-times"></i>',
            label: "Cancel"
          }
        },
        default: "apply"
      }).render(true);
    });

    // Set Name Display
    html.find('#set-name-display').click(() => {
      new Dialog({
        title: "Token Name Display Settings",
        content: `
          <div style="display: flex; flex-direction: column; gap: 10px; padding: 10px 0;">
            <label for="displayMode">Select Display Mode:</label>
            <select id="displayMode" style="padding: 5px;">
              <option value="${CONST.TOKEN_DISPLAY_MODES.HOVER}">Show on Hover</option>
              <option value="${CONST.TOKEN_DISPLAY_MODES.ALWAYS}">Show Always</option>
              <option value="${CONST.TOKEN_DISPLAY_MODES.OWNER_HOVER}">Show to Owner on Hover</option>
              <option value="${CONST.TOKEN_DISPLAY_MODES.OWNER}">Show to Owner Always</option>
              <option value="${CONST.TOKEN_DISPLAY_MODES.NONE}">Never Show</option>
            </select>
            <p>Updating ${selectedTokens.length} selected token(s)</p>
          </div>
        `,
        buttons: {
          apply: {
            icon: '<i class="fas fa-check"></i>',
            label: "Apply",
            callback: (innerHtml) => {
              const displayMode = parseInt(innerHtml.find('#displayMode').val());
              const tokenUpdates = selectedTokens.map(token => ({
                _id: token.id,
                "displayName": displayMode
              }));
              canvas.scene.updateEmbeddedDocuments('Token', tokenUpdates);
              ui.notifications.info(`Updated ${tokenUpdates.length} tokens with new display mode.`);
            }
          },
          cancel: {
            icon: '<i class="fas fa-times"></i>',
            label: "Cancel"
          }
        },
        default: "apply"
      }).render(true);
    });

    // Show Wounds
    html.find('#show-wounds').click(async () => {
      try {
        const tokenUpdates = selectedTokens.map(token => {
          if (token.document.disposition === CONST.TOKEN_DISPOSITIONS.HOSTILE) {
            return {
              _id: token.id,
              "bar1.attribute": "combat.wounds",
              "bar2.attribute": "",
              "displayName": CONST.TOKEN_DISPLAY_MODES.OWNER_HOVER,
              "displayBars": CONST.TOKEN_DISPLAY_MODES.HOVER
            };
          } else {
            return {
              _id: token.id,
              "bar1.attribute": "combat.wounds",
              "bar2.attribute": "",
              "displayName": CONST.TOKEN_DISPLAY_MODES.HOVER,
              "displayBars": CONST.TOKEN_DISPLAY_MODES.HOVER
            };
          }
        });

        await canvas.scene.updateEmbeddedDocuments('Token', tokenUpdates);
        ui.notifications.info(`Configured wounds display for ${tokenUpdates.length} tokens.`);
      } catch (error) {
        console.error("Error updating wounds display:", error);
        ui.notifications.error("Error configuring wounds display. Check console for details.");
      }
    });

    // Token Lights
    html.find('#token-lights').click(async () => {
      const states = new Set(Object.keys(lightConfigs));
      states.delete("def");

      const anyHasState = selectedTokens.some(token => 
        states.has(token.document.flags.world?.light)
      );

      if (anyHasState) {
        for (const token of selectedTokens) {
          await token.document.update({ 
            light: lightConfigs.def.config, 
            "flags.world.light": null 
          });
        }
        ui.notifications.info(`Disabled lights for ${selectedTokens.length} tokens.`);
      } else {
        const action = await new Promise((resolve) => {
          new Dialog({
            title: "Configure Token Light",
            content: `<p>Choose a light configuration for ${selectedTokens.length} selected tokens:</p>`,
            buttons: Array.from(states).map(state => {
              const label = lightConfigs[state].label;
              return {
                label: label,
                callback: () => resolve(state)
              };
            }),
            default: "cancel",
            close: () => resolve(null)
          }, {
            width: 400
          }).render(true);
        });

        if (action) {
          for (const token of selectedTokens) {
            await token.document.update({ 
              light: lightConfigs[action].config, 
              "flags.world.light": action 
            });
          }
          ui.notifications.info(`Applied ${lightConfigs[action].label} lights to ${selectedTokens.length} tokens.`);
        }
      }
    });

    // Add Auto-Attack
    html.find('#add-auto-attack').click(async () => {
      if (autoAttackUUID === "YOURUUIDHERE") {
        ui.notifications.error("Please set the Auto-Attack UUID in the macro code first!");
        return;
      }

      const traitItem = await fromUuid(autoAttackUUID);
      if (!traitItem) {
        ui.notifications.error("Auto-Attack trait item not found with the provided UUID.");
        return;
      }

      let addedCount = 0;
      let skippedCount = 0;
      const results = [];

      for (const t of selectedTokens) {
        const actor = t.actor;
        if (!actor) continue;

        const alreadyHas = actor.items.some(i =>
          i.getFlag?.("core", "sourceId") === autoAttackUUID ||
          i.name === traitItem.name
        );

        if (alreadyHas) {
          skippedCount++;
          results.push(`Skipped (already has): ${actor.name}`);
          continue;
        }

        await actor.createEmbeddedDocuments("Item", [traitItem.toObject()]);
        addedCount++;
        results.push(`Added to: ${actor.name}`);
      }

      const total = selectedTokens.length;
      ui.notifications.info(
        `Processed ${total} token(s): Added ${addedCount}, Skipped ${skippedCount}.`
      );
      console.log(results.join("\n"));
    });

    // Remove Auto-Attack
    html.find('#remove-auto-attack').click(async () => {
      if (autoAttackUUID === "YOURUUIDHERE") {
        ui.notifications.error("Please set the Auto-Attack UUID in the macro code first!");
        return;
      }

      let traitItem = null;
      try {
        traitItem = await fromUuid(autoAttackUUID);
      } catch (err) {
        console.warn("Could not resolve trait UUID; will only try sourceId matching.", err);
      }

      let totalRemoved = 0;
      let actorsTouched = 0;

      for (const token of selectedTokens) {
        const actor = token.actor;
        if (!actor) continue;

        const toRemove = actor.items.filter(i =>
          i.getFlag?.("core", "sourceId") === autoAttackUUID ||
          (traitItem && i.name === traitItem.name)
        );

        if (toRemove.length > 0) {
          await actor.deleteEmbeddedDocuments(
            "Item",
            toRemove.map(i => i.id)
          );
          totalRemoved += toRemove.length;
          actorsTouched += 1;
          console.log(`Removed ${toRemove.length} item(s) from ${actor.name}:`, toRemove.map(i => i.name));
        } else {
          console.log(`No matching item found on ${actor.name}.`);
        }
      }

      if (totalRemoved > 0) {
        ui.notifications.info(`Removed ${totalRemoved} item(s) from ${actorsTouched} actor(s).`);
      } else {
        ui.notifications.warn("No matching items found to remove. Double-check the UUID or item name.");
      }
    });

    // Set Disposition
    html.find('#set-disposition').click(() => {
      new Dialog({
        title: "Set Token Disposition",
        content: `
          <div style="display: flex; flex-direction: column; gap: 10px; padding: 10px;">
            <label for="disposition-select">Select Disposition:</label>
            <select id="disposition-select" style="margin-bottom: 10px;">
              <option value="${CONST.TOKEN_DISPOSITIONS.HOSTILE}">Hostile</option>
              <option value="${CONST.TOKEN_DISPOSITIONS.NEUTRAL}">Neutral</option>
              <option value="${CONST.TOKEN_DISPOSITIONS.FRIENDLY}">Friendly</option>
            </select>
            <p>This will affect ${selectedTokens.length} selected token(s)</p>
          </div>
        `,
        buttons: {
          set: {
            icon: '<i class="fas fa-check"></i>',
            label: "Set Disposition",
            callback: (innerHtml) => {
              const disposition = parseInt(innerHtml.find('#disposition-select').val());

              const updates = selectedTokens.map(token => ({
                _id: token.id,
                disposition: disposition
              }));

              canvas.scene.updateEmbeddedDocuments('Token', updates);

              ui.notifications.info(`Set disposition for ${selectedTokens.length} token(s)`);
            }
          },
          cancel: {
            icon: '<i class="fas fa-times"></i>',
            label: "Cancel"
          }
        },
        default: "set"
      }).render(true);
    });
  },
  default: "close"
}).render(true);
